// ===================================================
// CRM Proxy: 인증 + 요청 검증 + NocoDB URL 구성
// ===================================================

const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};

// --- 1. API Key 인증 ---
const apiKey = (headers['x-crm-key'] || '').trim();
if (!apiKey || apiKey !== $env.CRM_API_KEY) {
  return [{
    json: {
      _status: 401,
      _error: true,
      success: false,
      error: { code: 'UNAUTHORIZED', message: '인증에 실패했습니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

// --- 2. 필수 파라미터 검증 ---
const table = (body.table || '').trim();
const method = (body.method || 'GET').toUpperCase();
const recordId = body.recordId ? String(body.recordId).trim() : '';
const params = body.params || {};
const payload = body.payload || null;

if (!table) {
  return [{
    json: {
      _status: 400,
      _error: true,
      success: false,
      error: { code: 'MISSING_TABLE', message: 'table 파라미터가 필요합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

// --- 3. 테이블 화이트리스트 ---
// CRM(Offline) Base 테이블만 허용
const ALLOWED_TABLES = {
  'customers':  'mffgxkftaeppyk0',
  'products':   'mioztktmluobmmo',
  'invoices':   'ml81i9mcuw0pjzk',
  'items':      'mxwgdlj56p9joxo',
  'suppliers':  'mw6y9qyzex7lix9',
  'txHistory':  'mtxh72a1f4beeac'
};

const tableId = ALLOWED_TABLES[table];
if (!tableId) {
  return [{
    json: {
      _status: 400,
      _error: true,
      success: false,
      error: { code: 'INVALID_TABLE', message: '허용되지 않는 테이블: ' + table },
      timestamp: new Date().toISOString()
    }
  }];
}

// --- 4. HTTP Method 화이트리스트 ---
const ALLOWED_METHODS = ['GET', 'POST', 'PATCH', 'DELETE'];
if (!ALLOWED_METHODS.includes(method)) {
  return [{
    json: {
      _status: 400,
      _error: true,
      success: false,
      error: { code: 'INVALID_METHOD', message: '허용되지 않는 메서드: ' + method },
      timestamp: new Date().toISOString()
    }
  }];
}

// --- 5. 쓰기 작업 테이블 제한 (txHistory는 읽기 전용) ---
const READ_ONLY_TABLES = ['txHistory'];
if (READ_ONLY_TABLES.includes(table) && method !== 'GET') {
  return [{
    json: {
      _status: 403,
      _error: true,
      success: false,
      error: { code: 'READ_ONLY', message: table + ' 테이블은 읽기 전용입니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

// --- 6. NocoDB URL 구성 ---
const CRM_PROJECT_ID = 'pu0mwk97kac8a5p';
let path = tableId;

// bulk 오퍼레이션 처리
if (body.bulk) {
  path = tableId + '/bulk';
} else if (recordId) {
  // recordId 숫자 검증 (SQL injection 방지)
  if (!/^\d+$/.test(recordId)) {
    return [{
      json: {
        _status: 400,
        _error: true,
        success: false,
        error: { code: 'INVALID_ID', message: 'recordId는 숫자여야 합니다.' },
        timestamp: new Date().toISOString()
      }
    }];
  }
  path = tableId + '/' + recordId;
}

const nocodbUrl = 'https://nocodb.pressco21.com/api/v1/db/data/noco/' + CRM_PROJECT_ID + '/' + path;

// --- 7. 쿼리 파라미터 정제 (허용된 것만 전달) ---
const ALLOWED_PARAMS = ['where', 'limit', 'offset', 'sort', 'fields', 'shuffle', 'page'];
const cleanParams = {};
for (const key of ALLOWED_PARAMS) {
  if (params[key] !== undefined && params[key] !== null && params[key] !== '') {
    cleanParams[key] = String(params[key]);
  }
}

// limit 상한 설정 (DoS 방지)
if (cleanParams.limit) {
  const limit = parseInt(cleanParams.limit, 10);
  cleanParams.limit = String(Math.min(Math.max(limit || 25, 1), 200));
}

return [{
  json: {
    _error: false,
    _status: 200,
    nocodbUrl,
    method,
    params: cleanParams,
    payload,
    table,
    bulk: !!body.bulk
  }
}];

// ===================================================
// NocoDB 응답을 CRM 클라이언트 형식으로 변환
// ===================================================

const response = $input.first().json;
const statusCode = response.statusCode || 200;
const body = response.body || response;

// NocoDB 오류 처리
if (statusCode >= 400) {
  const errorMsg = (typeof body === 'string') ? body : (body.msg || body.message || 'NocoDB 오류');
  return [{
    json: {
      _status: statusCode,
      success: false,
      error: {
        code: 'NOCODB_ERROR',
        message: errorMsg
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// 정상 응답 전달
return [{
  json: {
    _status: 200,
    success: true,
    data: body,
    timestamp: new Date().toISOString()
  }
}];
